+fn extract_message_timestamp(msg: &serde_json::Value) -> Option<i64> {
+    msg.get("timestamp")
+        .and_then(crate::connectors::parse_timestamp)
+        .or_else(|| {
+            msg.get("message")
+                .and_then(|m| m.get("timestamp"))
+                .and_then(crate::connectors::parse_timestamp)
+        })
+        .or_else(|| {
+            msg.get("payload")
+                .and_then(|p| p.get("timestamp"))
+                .and_then(crate::connectors::parse_timestamp)
+        })
+}
